function solve(n, edges, label) {
    // Build adjacency list
    const adj = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let maxLen = 1; // At least one character can form a palindrome

    // We'll use BFS with a state that includes the current node, visited mask, and frequency count
    const queue = [];
    for (let i = 0; i < n; i++) {
        const mask = 1 << i;
        const freq = new Array(26).fill(0);
        freq[label.charCodeAt(i) - 97]++;
        queue.push([i, mask, freq]);
    }

    while (queue.length > 0) {
        const [node, mask, freq] = queue.shift();

        // Check if current frequency can form a palindrome
        let oddCount = 0;
        let total = 0;
        for (const count of freq) {
            if (count % 2 !== 0) {
                oddCount++;
            }
            total += count;
        }
        if (oddCount <= 1 && total > maxLen) {
            maxLen = total;
        }

        // Explore neighbors
        for (const neighbor of adj[node]) {
            if (!(mask & (1 << neighbor))) {
                const newMask = mask | (1 << neighbor);
                const newFreq = [...freq];
                newFreq[label.charCodeAt(neighbor) - 97]++;
                queue.push([neighbor, newMask, newFreq]);
            }
        }
    }

    return maxLen;
}

