use std::collections::VecDeque;

fn solve(n: i64, edges: Vec<Vec<i64>>, label: String) -> i64 {
    let n = n as usize;
    let mut adj = vec![vec![]; n];
    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        adj[u].push(v);
        adj[v].push(u);
    }

    let mut max_len = 1;
    let mut queue = VecDeque::new();
    let label_bytes = label.as_bytes();

    for i in 0..n {
        let mask = 1 << i;
        let mut freq = vec![0; 26];
        freq[(label_bytes[i] - b'a') as usize] += 1;
        queue.push_back((i, mask, freq));
    }

    while let Some((node, mask, freq)) = queue.pop_front() {
        let mut odd_count = 0;
        let mut total = 0;
        for &count in &freq {
            if count % 2 != 0 {
                odd_count += 1;
            }
            total += count;
        }
        if odd_count <= 1 && total > max_len {
            max_len = total;
        }

        for &neighbor in &adj[node] {
            if (mask & (1 << neighbor)) == 0 {
                let new_mask = mask | (1 << neighbor);
                let mut new_freq = freq.clone();
                new_freq[(label_bytes[neighbor] - b'a') as usize] += 1;
                queue.push_back((neighbor, new_mask, new_freq));
            }
        }
    }

    max_len as i64
}
